static int
process_jcf_constant_pool(struct jcf_state *jcf)
{
	int i;
	uint16_t constant_pool_count;
	uint8_t tag;

	assert(jcf != NULL);
	assert(jcf->constant_pool.pool == NULL);

	// Read the constant pool count.
	if (fread(&constant_pool_count, sizeof(constant_pool_count), 1, jcf->f) != 1)
		return (-1);
	constant_pool_count = ntohs(constant_pool_count);

	// Allocate the constant pool.
	jcf->constant_pool.count = constant_pool_count;
	jcf->constant_pool.pool = calloc(constant_pool_count, sizeof(struct jcf_cp_info *));
	if (jcf->constant_pool.pool == NULL)
		return (-1);

	// Read the constant pool.
	for (i = 1; i < constant_pool_count; i++) {
		// Read the constant pool info tag.
		if (fread(&tag, sizeof(tag), 1, jcf->f) != 1)
			return (-1);

		// Process the rest of the constant info.
		switch (tag) {
		case JCF_CONSTANT_String:
		case JCF_CONSTANT_Class:
		case JCF_CONSTANT_MethodType: {
			// Read a constant that contains one u2.
			struct jcf_cp_info_1u2 *info = malloc(sizeof(struct jcf_cp_info_1u2));
			if (info == NULL) return (-1);
			info->tag = tag;
			if (fread(&info->u2, sizeof(info->u2), 1, jcf->f) != 1) {
				free(info);
				return (-1);
			}
			info->u2 = ntohs(info->u2);
			jcf->constant_pool.pool[i] = (struct jcf_cp_info *)info;
			break;
		}
		case JCF_CONSTANT_Fieldref:
		case JCF_CONSTANT_Methodref:
		case JCF_CONSTANT_InterfaceMethodref:
		case JCF_CONSTANT_NameAndType:
		case JCF_CONSTANT_InvokeDynamic: {
			// Read a constant that contains two u2's.
			struct jcf_cp_info_2u2 *info = malloc(sizeof(struct jcf_cp_info_2u2));
			if (info == NULL) return (-1);
			info->tag = tag;
			if (fread(&info->body, sizeof(info->body), 1, jcf->f) != 1) {
				free(info);
				return (-1);
			}
			info->body.u2_1 = ntohs(info->body.u2_1);
			info->body.u2_2 = ntohs(info->body.u2_2);
			jcf->constant_pool.pool[i] = (struct jcf_cp_info *)info;
			break;
		}
		case JCF_CONSTANT_Integer:
		case JCF_CONSTANT_Float: {
			// Read a constant that contains one u4.
			struct jcf_cp_info_1u4 *info = malloc(sizeof(struct jcf_cp_info_1u4));
			if (info == NULL) return (-1);
			info->tag = tag;
			if (fread(&info->u4, sizeof(info->u4), 1, jcf->f) != 1) {
				free(info);
				return (-1);
			}
			info->u4 = ntohl(info->u4);
			jcf->constant_pool.pool[i] = (struct jcf_cp_info *)info;
			break;
		}
		case JCF_CONSTANT_Long:
		case JCF_CONSTANT_Double: {
			/* 
			 * Read a constant that contains two u4's and
			 * occupies two indices in the constant pool. 
			 */
			struct jcf_cp_info_2u2 *info = malloc(sizeof(struct jcf_cp_info_2u2)); // Reusing 2u2 as it has 2 u4's space? No, 2u2 has 2 u2's. Wait. 
			// Long and Double have 8 bytes. Let's use a 1u8 or just read two u4s.
			// Actually let's use a custom struct or just allocate 9 bytes.
			struct jcf_cp_info *long_info = malloc(1 + 8);
			if (long_info == NULL) return (-1);
			long_info->tag = tag;
			if (fread(long_info->info, 8, 1, jcf->f) != 1) {
				free(long_info);
				return (-1);
			}
			jcf->constant_pool.pool[i] = long_info;
			i++; // Skip next index.
			break;
		}
		case JCF_CONSTANT_Utf8: {
			// Read a UTF8 constant.
			uint16_t length;
			if (fread(&length, sizeof(length), 1, jcf->f) != 1)
				return (-1);
			length = ntohs(length);
			struct jcf_cp_utf8_info *info = malloc(sizeof(struct jcf_cp_utf8_info) + length + 1);
			if (info == NULL) return (-1);
			info->tag = tag;
			info->length = length;
			if (length > 0) {
				if (fread(info->bytes, length, 1, jcf->f) != 1) {
					free(info);
					return (-1);
				}
			}
			info->bytes[length] = '\0'; // NUL terminate.
			jcf->constant_pool.pool[i] = (struct jcf_cp_info *)info;
			break;
		}
		case JCF_CONSTANT_MethodHandle: {
			// Read a constant that contains one u1 and one u2.
			struct jcf_cp_info_1u1_1u2 *info = malloc(sizeof(struct jcf_cp_info_1u1_1u2));
			if (info == NULL) return (-1);
			info->tag = tag;
			if (fread(&info->body, sizeof(info->body), 1, jcf->f) != 1) {
				free(info);
				return (-1);
			}
			info->body.u2 = ntohs(info->body.u2);
			jcf->constant_pool.pool[i] = (struct jcf_cp_info *)info;
			break;
		}
		default:
			return (-1);
		}
	}

	/* 
	 * Print the dependencies if requested.  This must be done after
	 * reading the entire pool because there are no guarantees about
	 * constants not containing references to other constants after
	 * them in the pool. 
	 */
	if (jcf->depends_flag) {
		for (i = 1; i < constant_pool_count; i++) {
			struct jcf_cp_info *info = jcf->constant_pool.pool[i];
			if (info == NULL) continue;
			if (info->tag == JCF_CONSTANT_Fieldref ||
			    info->tag == JCF_CONSTANT_Methodref ||
			    info->tag == JCF_CONSTANT_InterfaceMethodref) {
				printf("Dependency - ");
				if (print_jcf_constant(jcf, i, info->tag) != 0)
					return (-1);
				printf("\n");
			}
		}
	}

	return (0);
}

static int
print_jcf_constant(struct jcf_state *jcf, uint16_t index,
    uint8_t expected_tag)
{
	struct jcf_cp_info *info;

	assert(jcf != NULL);

	// Verify the index.
	if (index == 0 || index >= jcf->constant_pool.count)
		return (-1);

	info = jcf->constant_pool.pool[index];
	if (info == NULL)
		return (-1);

	// Verify the tag.
	if (expected_tag != 0 && info->tag != expected_tag)
		return (-1);

	// Print the constant.
	switch (info->tag) {
	case JCF_CONSTANT_Class: {
		struct jcf_cp_class_info *class_info = (struct jcf_cp_class_info *)info;
		if (print_jcf_constant(jcf, class_info->name_index, JCF_CONSTANT_Utf8) != 0)
			return (-1);
		break;
	}
	case JCF_CONSTANT_Fieldref:
	case JCF_CONSTANT_Methodref:
	case JCF_CONSTANT_InterfaceMethodref: {
		struct jcf_cp_ref_info *ref_info = (struct jcf_cp_ref_info *)info;
		if (print_jcf_constant(jcf, ref_info->class_index, JCF_CONSTANT_Class) != 0)
			return (-1);
		printf(".");
		if (print_jcf_constant(jcf, ref_info->name_and_type_index, JCF_CONSTANT_NameAndType) != 0)
			return (-1);
		break;
	}
	case JCF_CONSTANT_NameAndType: {
		struct jcf_cp_nameandtype_info *nt_info = (struct jcf_cp_nameandtype_info *)info;
		if (print_jcf_constant(jcf, nt_info->name_index, JCF_CONSTANT_Utf8) != 0)
			return (-1);
		printf(" ");
		if (print_jcf_constant(jcf, nt_info->descriptor_index, JCF_CONSTANT_Utf8) != 0)
			return (-1);
		break;
	}
	case JCF_CONSTANT_Utf8: {
		struct jcf_cp_utf8_info *utf8_info = (struct jcf_cp_utf8_info *)info;
		printf("%s", utf8_info->bytes);
		break;
	}
	default:
		// Ignore all other constants.
		break;
	}

	return (0);
}

